```python
class Pickleable(HasTraits):

    i = Int()
    @observe('i')
    def _i_changed(self, change): pass
    @validate('i')
    def _i_validate(self, commit):
        return commit['value']
```
pass tests, but would have failed to pickle

Fixes issue #912. Recursive calls now work.
```from manticore.ethereum import ManticoreEVM

m = ManticoreEVM(workspace_url="bug")
m.verbosity(3)
owner_account = m.create_account(balance=1000)

c = '''
contract C1 { 
  function f() returns (uint) {
    return 1;
  }
}

contract C2 { 
  address c;
  function C2(address x) {
    c = x;
  }
  function f() returns (uint) {
    return C1(c).f();
  }
}
'''

c1 = m.solidity_create_contract(c, owner=owner_account, contract_name='C1')
c2 = m.solidity_create_contract(c, owner=owner_account, contract_name='C2', args=[c1.address])
c2.f();
c2.f();```

